post_expected<Eigen::MatrixXd>
invert_spd(const Eigen::MatrixXd& M, const char* what) {
  Eigen::LLT<Eigen::MatrixXd> llt(M);
  if (llt.info() != Eigen::Success) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
                                    std::string(what) +
                                        " is not positive definite"));
  }
  return llt.solve(Eigen::MatrixXd::Identity(M.rows(), M.cols()));
}

double residual_z(double residual, double se) noexcept {
  if (std::abs(residual) < 1e-4) return residual;
  if (!std::isfinite(se) || se == 0.0) {
    return std::numeric_limits<double>::quiet_NaN();
  }
  return residual / se;
}

// Standard-normal CDF (Φ). NaN-propagating, so a non-finite z flows through to
// a non-finite p-value — matching lavaan's `1 - pnorm(NA) == NA`.
double std_normal_cdf(double z) noexcept {
  return 0.5 * std::erfc(-z * 0.70710678118654752440);  // -z / √2
}

// Standard-normal quantile (Acklam's rational approximation, ~1.15e-9 abs error
// — well inside the summary's parity tolerance). Mirrors the `inv_normal_cdf`
// used in the ordinal misspec-CI path.
double std_normal_quantile(double p) noexcept {
  p = std::clamp(p, 1e-12, 1.0 - 1e-12);
  static constexpr double a[] = {
      -3.969683028665376e+01, 2.209460984245205e+02, -2.759285104469687e+02,
      1.383577518672690e+02, -3.066479806614716e+01, 2.506628277459239e+00};
  static constexpr double b[] = {
      -5.447609879822406e+01, 1.615858368580409e+02, -1.556989798598866e+02,
      6.680131188771972e+01, -1.328068155288572e+01};
  static constexpr double c[] = {
      -7.784894002430293e-03, -3.223964580411365e-01, -2.400758277161838e+00,
      -2.549732539343734e+00, 4.374664141464968e+00, 2.938163982698783e+00};
  static constexpr double d[] = {
      7.784695709041462e-03, 3.224671290700398e-01, 2.445134137142996e+00,
      3.754408661907416e+00};
  constexpr double plow = 0.02425;
  constexpr double phigh = 1.0 - plow;
  if (p < plow) {
    const double q = std::sqrt(-2.0 * std::log(p));
    return (((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q +
            c[5]) /
           ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1.0);
  }
  if (p > phigh) {
    const double q = std::sqrt(-2.0 * std::log(1.0 - p));
    return -(((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q +
             c[5]) /
           ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1.0);
  }
  const double q = p - 0.5;
  const double r = q * q;
  return (((((a[0] * r + a[1]) * r + a[2]) * r + a[3]) * r + a[4]) * r + a[5]) *
         q /
         (((((b[0] * r + b[1]) * r + b[2]) * r + b[3]) * r + b[4]) * r + 1.0);
}

// Root-mean-square residual summary for one section (cov / mean / total) — a
// direct port of lavaan's `lav_residuals_summary_rms` with the `lavResiduals`
// defaults (se, zstat, pvalue, unbiased, unbiased.se/ci/zstat/pvalue all on).
// `stats` is the residual vector, `acov` its (cor.bentler) ACOV, `pstar` the
// moment count the RMS averages over. An empty section returns rms = 0 with the
// inferential fields left NaN (lavaan disables se/zstat/unbiased there).
ResidualRms residual_rms(const Eigen::VectorXd& stats,
                         const Eigen::MatrixXd& acov, double pstar,
                         double conf_level, double h0) noexcept {
  ResidualRms r;
  r.usrmr_closefit_h0 = h0;
  if (stats.size() == 0 || pstar <= 0.0) {
    r.srmr = 0.0;
    return r;
  }
  constexpr double eps = std::numeric_limits<double>::epsilon();
  const double sumsq = stats.squaredNorm();
  r.srmr = std::sqrt(sumsq / pstar);

  const double tr1 = acov.trace();
  const double tr2 = (acov * acov).trace();

  // SE of the (biased) RMS.
  const double rms_avar = tr2 / (tr1 * 2.0 * pstar);
  r.srmr_se = (std::isfinite(rms_avar) && rms_avar >= eps)
                  ? std::sqrt(rms_avar)
                  : std::numeric_limits<double>::quiet_NaN();

  // Exact-fit z-test (H0: population RMS == 0).
  const double e_rms =
      std::sqrt(tr1 / pstar) * (4.0 * tr1 * tr1 - tr2) / (4.0 * tr1 * tr1);
  r.srmr_exactfit_z = std::max(r.srmr - e_rms, 0.0) / r.srmr_se;
  r.srmr_exactfit_pvalue = 1.0 - std_normal_cdf(r.srmr_exactfit_z);

  // Bias-corrected RMS + close-fit inference.
  const double t_cov = sumsq;
  const double eve = stats.dot(acov * stats);
  const double k_cov = 1.0 - (tr2 + 2.0 * eve) / (4.0 * t_cov * t_cov);
  r.usrmr = (1.0 / k_cov) * std::sqrt(std::max(t_cov - tr1, 0.0) / pstar);
  const double urms_avar =
      (1.0 / (k_cov * k_cov)) * (tr2 + 2.0 * eve) / (2.0 * pstar * t_cov);
  r.usrmr_se = (std::isfinite(urms_avar) && urms_avar >= eps)
                   ? std::sqrt(urms_avar)
                   : std::numeric_limits<double>::quiet_NaN();
  const double za = std_normal_quantile(0.5 * (1.0 - conf_level));  // qnorm(.05)
  r.usrmr_ci_lower = r.usrmr + r.usrmr_se * za;
  r.usrmr_ci_upper = r.usrmr - r.usrmr_se * za;
  r.usrmr_closefit_z = (r.usrmr - h0) / r.usrmr_se;
  r.usrmr_closefit_pvalue = 1.0 - std_normal_cdf(r.usrmr_closefit_z);
  return r;
}

// Standardize one block's residual moment ACOV (`acov_res`, [μ ; vech σ] layout,
// already symmetrized, dims moment_rows = (has_mean?p:0)+p(p+1)/2) into the
// correlation-metric residual SE/z matrices and the cor.bentler RMS `$summary`,
// appending them to `out`. Shared by the NT residual path (`fill_residual_z`)
// and the estimated-weight frontier path; assumes `out.cov_cor[b]` /
// `out.mean_cor[b]` are already filled.
void apply_residual_standardization(StandardizedResiduals& out, std::size_t b,
                                    const Eigen::MatrixXd& S, bool has_mean,
                                    const Eigen::MatrixXd& acov_res,
                                    double conf_level) {
  const Eigen::Index p = S.rows();
  const Eigen::Index pstar = vech_len(p);
  const Eigen::Index cov_off = has_mean ? p : 0;
  const Eigen::Index moment_rows = (has_mean ? p : 0) + pstar;

  Eigen::MatrixXd cov_se = Eigen::MatrixXd::Zero(p, p);
  Eigen::MatrixXd cov_z = Eigen::MatrixXd::Zero(p, p);
  for (Eigen::Index c = 0; c < p; ++c) {
    for (Eigen::Index r = c; r < p; ++r) {
      const Eigen::Index row = cov_off + vech_index(p, r, c);
      const double denom = std::sqrt(S(r, r) * S(c, c));
      const double scale = (denom != 0.0) ? 1.0 / denom : 0.0;
      const double var = scale * scale * acov_res(row, row);
      const double se = (var >= 0.0)
          ? std::sqrt(var)
          : std::numeric_limits<double>::quiet_NaN();
      const double z = residual_z(out.cov_cor[b](r, c), se);
      cov_se(r, c) = se;
      cov_z(r, c) = z;
      if (r != c) {
        cov_se(c, r) = se;
        cov_z(c, r) = z;
      }
    }
  }
  out.cov_se.push_back(std::move(cov_se));
  out.cov_z.push_back(std::move(cov_z));

  if (has_mean) {
    Eigen::VectorXd mean_se(p);
    Eigen::VectorXd mean_z(p);
    for (Eigen::Index i = 0; i < p; ++i) {
      const double scale = (S(i, i) != 0.0) ? 1.0 / std::sqrt(S(i, i)) : 0.0;
      const double var = scale * scale * acov_res(i, i);
      const double se = (var >= 0.0)
          ? std::sqrt(var)
          : std::numeric_limits<double>::quiet_NaN();
      mean_se(i) = se;
      mean_z(i) = residual_z(out.mean_cor[b](i), se);
    }
    out.mean_se.push_back(std::move(mean_se));
    out.mean_z.push_back(std::move(mean_z));
  } else {
    out.mean_se.emplace_back();
    out.mean_z.emplace_back();
  }

  // lavResiduals(fit)$summary — the cor.bentler RMS family. Scale the raw-metric
  // residual ACOV into the correlation metric by a diagonal congruence
  // (Ogasawara 2001 eq. 13): a vech(cov) row (r,c) by 1/√(s_rr·s_cc), a mean row
  // i by 1/√(s_ii). The standardized residuals are the STATS the RMS averages.
  Eigen::VectorXd gg(moment_rows);
  if (has_mean) {
    for (Eigen::Index i = 0; i < p; ++i)
      gg(i) = (S(i, i) > 0.0) ? 1.0 / std::sqrt(S(i, i)) : 0.0;
  }
  for (Eigen::Index c = 0; c < p; ++c)
    for (Eigen::Index r = c; r < p; ++r) {
      const double denom = std::sqrt(S(r, r) * S(c, c));
      gg(cov_off + vech_index(p, r, c)) = (denom > 0.0) ? 1.0 / denom : 0.0;
    }
  Eigen::MatrixXd acov_cor = acov_res;
  for (Eigen::Index i = 0; i < moment_rows; ++i)
    for (Eigen::Index j = 0; j < moment_rows; ++j)
      acov_cor(i, j) *= gg(i) * gg(j);

  Eigen::VectorXd stats_total(moment_rows);
  if (has_mean)
    for (Eigen::Index i = 0; i < p; ++i) stats_total(i) = out.mean_cor[b](i);
  for (Eigen::Index c = 0; c < p; ++c)
    for (Eigen::Index r = c; r < p; ++r)
      stats_total(cov_off + vech_index(p, r, c)) = out.cov_cor[b](r, c);

  ResidualSummary summ;
  summ.has_mean = has_mean;
  summ.cov = residual_rms(stats_total.segment(cov_off, pstar),
                          acov_cor.block(cov_off, cov_off, pstar, pstar),
                          static_cast<double>(pstar), conf_level, 0.05);
  if (has_mean) {
    summ.mean = residual_rms(stats_total.head(p), acov_cor.topLeftCorner(p, p),
                             static_cast<double>(p), conf_level, 0.05);
    summ.total = residual_rms(stats_total, acov_cor,
                              static_cast<double>(moment_rows), conf_level, 0.05);
  }
  out.summary.push_back(std::move(summ));
}

post_expected<void>
fill_residual_z(spec::LatentStructure pt, const model::MatrixRep& rep,
                const SampleStats& samp, const Estimates& est,
                double conf_level, StandardizedResiduals& out) {
  if (auto e = estimate::resolve_fixed_x_from_sample(pt, rep, samp);
      !e.has_value()) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
        "resolve_fixed_x_from_sample failed: " + e.error().detail));
  }
  auto ev_or = model::ModelEvaluator::build(pt, rep);
  if (!ev_or.has_value()) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
        "ModelEvaluator::build failed: " + ev_or.error().detail));
  }
  const auto& ev = *ev_or;

  auto sm_or = ev.sigma(est.theta);
  if (!sm_or.has_value()) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
        "ev.sigma(θ̂) failed: " + sm_or.error().detail));
  }
  const auto& sm = *sm_or;

  auto J_or = ev.dsigma_dtheta(est.theta);
  if (!J_or.has_value()) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
        "ev.dsigma_dtheta(θ̂) failed: " + J_or.error().detail));
  }
  const Eigen::MatrixXd& J_sigma = *J_or;

  auto Jmu_or = ev.dmu_dtheta(est.theta);
  if (!Jmu_or.has_value()) {
    return std::unexpected(make_err(PostError::Kind::NumericIssue,
        "ev.dmu_dtheta(θ̂) failed: " + Jmu_or.error().detail));
  }
  const Eigen::MatrixXd& J_mu = *Jmu_or;

  auto info_or = inference::information_expected(pt, rep, samp, est);
  if (!info_or.has_value()) return std::unexpected(info_or.error());
  auto vcov_or = inference::vcov(*info_or, pt, est.theta);
  if (!vcov_or.has_value()) return std::unexpected(vcov_or.error());
  const Eigen::MatrixXd& V = *vcov_or;

  out.cov_se.clear();
  out.cov_z.clear();
  out.mean_se.clear();
  out.mean_z.clear();
  out.summary.clear();
  out.cov_se.reserve(out.cov_cor.size());
  out.cov_z.reserve(out.cov_cor.size());
  out.mean_se.reserve(out.mean_cor.size());
  out.mean_z.reserve(out.mean_cor.size());
  out.summary.reserve(out.cov_cor.size());

  Eigen::Index sigma_cursor = 0;
  Eigen::Index mu_cursor = 0;
  for (std::size_t b = 0; b < samp.S.size(); ++b) {
    if (samp.n_obs.size() <= b) {
      return std::unexpected(make_err(PostError::Kind::NumericIssue,
          "SampleStats is missing n_obs for a residual block"));
    }
    const Eigen::MatrixXd S = 0.5 * (samp.S[b] + samp.S[b].transpose());
    const Eigen::MatrixXd Sigma =
        0.5 * (sm.sigma[b] + sm.sigma[b].transpose());
    const Eigen::Index p = S.rows();
    const Eigen::Index pstar = vech_len(p);
    const bool has_mean =
        out.mean_cor.size() > b && out.mean_cor[b].size() == p &&
        J_mu.size() > 0;
    const Eigen::Index moment_rows = (has_mean ? p : 0) + pstar;
    const Eigen::Index cov_off = has_mean ? p : 0;
    const double n_b = static_cast<double>(samp.n_obs[b]);
    if (n_b <= 0.0) {
      return std::unexpected(make_err(PostError::Kind::NumericIssue,
          "SampleStats has a non-positive n_obs in residual z-statistics"));
    }

    auto G_obs_or = data::gamma_nt(S);
    if (!G_obs_or.has_value()) return std::unexpected(G_obs_or.error());
    auto G_model_or = data::gamma_nt(Sigma);
    if (!G_model_or.has_value()) return std::unexpected(G_model_or.error());
    auto G_model_inv_or = invert_spd(*G_model_or, "model-implied Γ_NT");
    if (!G_model_inv_or.has_value()) {
      return std::unexpected(G_model_inv_or.error());
    }

    Eigen::MatrixXd acov_obs =
        Eigen::MatrixXd::Zero(moment_rows, moment_rows);
    Eigen::MatrixXd h1_info =
        Eigen::MatrixXd::Zero(moment_rows, moment_rows);
    if (has_mean) {
      auto Sigma_inv_or = invert_spd(Sigma, "model-implied Σ");
      if (!Sigma_inv_or.has_value()) {
        return std::unexpected(Sigma_inv_or.error());
      }
      acov_obs.topLeftCorner(p, p) = S / n_b;
      h1_info.topLeftCorner(p, p) = *Sigma_inv_or;
    }
    acov_obs.block(cov_off, cov_off, pstar, pstar) = *G_obs_or / n_b;
    h1_info.block(cov_off, cov_off, pstar, pstar) = *G_model_inv_or;

    Eigen::MatrixXd Delta = Eigen::MatrixXd::Zero(moment_rows, V.cols());
    if (has_mean) {
      if (mu_cursor + p > J_mu.rows()) {
        return std::unexpected(make_err(PostError::Kind::NumericIssue,
            "dmu_dtheta row count is too small for residual z-statistics"));
      }
      Delta.topRows(p) = J_mu.block(mu_cursor, 0, p, V.cols());
      mu_cursor += p;
    }
    if (sigma_cursor + pstar > J_sigma.rows()) {
      return std::unexpected(make_err(PostError::Kind::NumericIssue,
          "dsigma_dtheta row count is too small for residual z-statistics"));
    }
    Delta.block(cov_off, 0, pstar, V.cols()) =
        J_sigma.block(sigma_cursor, 0, pstar, V.cols());
    sigma_cursor += pstar;

    const Eigen::MatrixXd acov_est_unscaled =
        n_b * (Delta * V * Delta.transpose());
    const Eigen::MatrixXd Q =
        Eigen::MatrixXd::Identity(moment_rows, moment_rows) -
        acov_est_unscaled * h1_info;
    Eigen::MatrixXd acov_res = Q * acov_obs * Q.transpose();
    acov_res = 0.5 * (acov_res + acov_res.transpose()).eval();

    apply_residual_standardization(out, b, S, has_mean, acov_res, conf_level);
  }

  return {};
}

// Raw + correlation-metric residual matrices and the SRMR (everything in a
// `StandardizedResiduals` except the SE/z/summary blocks, which a downstream
// `acov_res` source fills). Shared by the NT and estimated-weight paths.
post_expected<StandardizedResiduals>
build_base_standardized(spec::LatentStructure pt, const model::MatrixRep& rep,
                        const SampleStats& samp, const Estimates& est,
                        double conf_level) {
  auto raw = residuals(pt, rep, samp, est);
  if (!raw.has_value()) return std::unexpected(raw.error());
  auto extras = fit_extras(pt, rep, samp, est);
  if (!extras.has_value()) return std::unexpected(extras.error());

  StandardizedResiduals out;
  out.srmr       = extras->srmr;
  out.conf_level = conf_level;
  out.cov_raw  = std::move(raw->cov);
  out.mean_raw = std::move(raw->mean);
  out.cov_cor.reserve(out.cov_raw.size());
  out.mean_cor.reserve(out.cov_raw.size());

  for (std::size_t b = 0; b < out.cov_raw.size(); ++b) {
    const Eigen::MatrixXd& S = samp.S[b];
    const Eigen::MatrixXd& r = out.cov_raw[b];
    const Eigen::Index p = r.rows();

    // Correlation-metric residual (Bentler standardization by the *sample* SDs)
    // — the same metric the SRMR sums over.
    Eigen::MatrixXd cor = Eigen::MatrixXd::Zero(p, p);
    for (Eigen::Index c = 0; c < p; ++c) {
      cor(c, c) = (S(c, c) != 0.0) ? r(c, c) / S(c, c) : 0.0;
      for (Eigen::Index rr = c + 1; rr < p; ++rr) {
        const double denom = std::sqrt(S(rr, rr) * S(c, c));
        const double v = (denom != 0.0) ? r(rr, c) / denom : 0.0;
        cor(rr, c) = v;
        cor(c, rr) = v;
      }
    }
    out.cov_cor.push_back(std::move(cor));

    // Mean residual in SD units — only when the block carries a mean.
    if (out.mean_raw[b].size() == p && p > 0) {
      Eigen::VectorXd mc(p);
      for (Eigen::Index i = 0; i < p; ++i)
        mc(i) = (S(i, i) != 0.0) ? out.mean_raw[b](i) / std::sqrt(S(i, i)) : 0.0;
      out.mean_cor.push_back(std::move(mc));
    } else {
      out.mean_cor.emplace_back();
    }
  }
  return out;
}

